package entity;

import java.awt.Rectangle;
import java.awt.image.BufferedImage;
import java.io.IOException;
import java.io.InputStream;
import java.util.Random;

import main.GamePanel;
import main.UtilityTool;

import javax.imageio.ImageIO;

public class Npc_HumanRedWorker extends Entity {

    public Npc_HumanRedWorker(GamePanel gp) {
        super(gp);

        direction = "down";
        speed = 1;

        solidArea = new Rectangle();
        solidArea.x = 8;
        solidArea.y = 16;
        solidAreaDefaultX = solidArea.x;
        solidAreaDefaultY = solidArea.y;
        solidArea.width = 32;
        solidArea.height = 32;

        getImage();
    }

    public BufferedImage setup(String imagePath, int width, int height) {

        UtilityTool uTool = new UtilityTool();
        BufferedImage image = null;

        try {

            image = ImageIO.read(getClass().getResourceAsStream(imagePath + ".png"));
            image = uTool.scaleImage(image, width, height);

        } catch (IOException e) {
            e.printStackTrace();
        }
        return image;
    }
    public void getImage() {
        up1 = setup("/npc/RedWorkerNpc_up_1", gp.tileSize, gp.tileSize);
        up2 = setup("/npc/RedWorkerNpc_up_2", gp.tileSize, gp.tileSize);
        down1 = setup("/npc/RedWorkerNpc__down_1", gp.tileSize, gp.tileSize);
        down2 = setup("/npc/RedWorkerNpc__down_2", gp.tileSize, gp.tileSize);
        left1 = setup("/npc/RedWorkerNpc__left_1", gp.tileSize, gp.tileSize);
        left2 = setup("/npc/RedWorkerNpc__left_2", gp.tileSize, gp.tileSize);
        right1 = setup("/npc/RedWorkerNpc__right_1", gp.tileSize, gp.tileSize);
        right2 = setup("/npc/RedWorkerNpc__right_2", gp.tileSize, gp.tileSize);
    }
    public void setAction() {
         actionLockCounter++;
            if (actionLockCounter == 120) {
                Random random = new Random();
                int i = random.nextInt(100) + 1;

                if (i <= 25) {
                    direction = "up";
                }
                if (i > 25 && i <= 50) {
                    direction = "down";
                }
                if (i > 50 && i <= 75) {
                    direction = "left";
                }
                if (i > 75 && i <= 100) {
                    direction = "right";
                }

                actionLockCounter = 0;
            }
        }
    }
